from __future__ import annotations

import hashlib
import logging
import os
from pathlib import Path
from typing import Optional

from nacl.signing import SigningKey, VerifyKey

logger = logging.getLogger(__name__)


def _key_id(verify_key: VerifyKey) -> str:
    return hashlib.sha256(bytes(verify_key)).hexdigest()[:16]


class KeyRing:
    """Manages Ed25519 signing/verification keys for the ledger."""

    def __init__(
        self,
        signing_key_path: Optional[str | Path] = None,
        verification_keys_dir: Optional[str | Path] = None,
    ) -> None:
        sk_path = signing_key_path or os.environ.get("THESEUS_LEDGER_SIGNING_KEY_PATH")
        vk_dir = verification_keys_dir or os.environ.get("THESEUS_LEDGER_VERIFICATION_KEYS_DIR")

        if sk_path is None:
            raise ValueError("Signing key path required (arg or THESEUS_LEDGER_SIGNING_KEY_PATH)")
        self._sk_path = Path(sk_path)
        self._signing_key = SigningKey(self._sk_path.read_bytes()[:32])
        self._active_key_id = _key_id(self._signing_key.verify_key)

        self._verify_keys: dict[str, VerifyKey] = {}
        self._verify_keys[self._active_key_id] = self._signing_key.verify_key

        if vk_dir is not None:
            self._vk_dir = Path(vk_dir)
            self._load_verification_keys()
        else:
            self._vk_dir = None

    def _load_verification_keys(self) -> None:
        if self._vk_dir is None or not self._vk_dir.is_dir():
            return
        for p in sorted(self._vk_dir.iterdir()):
            if p.is_file() and not p.name.startswith("."):
                try:
                    vk = VerifyKey(p.read_bytes()[:32])
                    kid = _key_id(vk)
                    self._verify_keys[kid] = vk
                except Exception:
                    logger.warning("Skipping invalid verification key: %s", p)

    @property
    def active_key_id(self) -> str:
        return self._active_key_id

    def sign(self, data: bytes) -> bytes:
        signed = self._signing_key.sign(data)
        return signed.signature

    def verify(self, data: bytes, signature: bytes, key_id: str) -> bool:
        vk = self._verify_keys.get(key_id)
        if vk is None:
            return False
        try:
            vk.verify(data, signature)
            return True
        except Exception:
            return False

    def rotate(self, new_key_path: str | Path) -> None:
        new_path = Path(new_key_path)
        new_sk = SigningKey(new_path.read_bytes()[:32])
        new_kid = _key_id(new_sk.verify_key)
        self._verify_keys[new_kid] = new_sk.verify_key
        self._signing_key = new_sk
        self._sk_path = new_path
        self._active_key_id = new_kid

    @staticmethod
    def generate_keypair(key_dir: Path) -> Path:
        """Generate a new Ed25519 keypair, saving to key_dir. Returns signing key path."""
        key_dir.mkdir(parents=True, exist_ok=True)
        sk = SigningKey.generate()
        sk_path = key_dir / "signing.key"
        sk_path.write_bytes(bytes(sk))
        vk_path = key_dir / "verify.pub"
        vk_path.write_bytes(bytes(sk.verify_key))
        return sk_path

"""CLI commands for the Ledger (append-only signed audit log) subsystem."""

from __future__ import annotations

import json
from datetime import datetime, timezone
from typing import Optional

import click
from rich.console import Console
from rich.table import Table

console = Console()


def _get_store():
    from noosphere.cli import get_orchestrator
    return get_orchestrator(None).store


def _parse_ts(val: Optional[str]) -> Optional[datetime]:
    if val is None:
        return None
    return datetime.fromisoformat(val).replace(tzinfo=timezone.utc)


@click.group("ledger")
def cli() -> None:
    """Ledger: verify chain integrity and export audit bundles."""


@cli.command("verify")
@click.option("--since", type=str, default=None, help="Start timestamp (ISO 8601)")
@click.option("--until", type=str, default=None, help="End timestamp (ISO 8601)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def verify(since: Optional[str], until: Optional[str], as_json: bool) -> None:
    """Verify ledger chain integrity and signatures."""
    from noosphere.ledger import KeyRing, verify as ledger_verify

    store = _get_store()
    keyring = KeyRing(store)
    report = ledger_verify(store, keyring, since=_parse_ts(since),
                           until=_parse_ts(until))
    if as_json:
        click.echo(json.dumps({
            "total_entries": report.total_entries,
            "chain_valid": report.chain_valid,
            "signatures_valid": report.signatures_valid,
            "ok": report.ok,
            "issues": [{"entry_id": i.entry_id, "issue_type": i.issue_type,
                        "detail": i.detail} for i in report.issues],
        }, indent=2, default=str))
        return
    style = "green" if report.ok else "red"
    table = Table(title="Ledger Verification", show_header=False)
    table.add_row("Total entries", str(report.total_entries))
    table.add_row("Chain valid", f"[{style}]{report.chain_valid}[/{style}]")
    table.add_row("Signatures valid", f"[{style}]{report.signatures_valid}[/{style}]")
    table.add_row("Issues", str(len(report.issues)))
    console.print(table)
    if report.issues:
        it = Table(title="Issues", show_header=True)
        it.add_column("Entry", style="yellow", max_width=12)
        it.add_column("Type")
        it.add_column("Detail", max_width=50)
        for issue in report.issues[:20]:
            it.add_row(issue.entry_id[:12], issue.issue_type, issue.detail[:50])
        console.print(it)


@cli.command("export")
@click.option("--from", "from_id", required=True, help="Starting ledger entry ID")
@click.option("--to", "to_id", required=True, help="Ending ledger entry ID")
@click.option("--out", "out_path", required=True, type=click.Path(),
              help="Output file path (.tar.gz)")
@click.option("--json", "as_json", is_flag=True, help="Output as JSON")
def export(from_id: str, to_id: str, out_path: str, as_json: bool) -> None:
    """Export a ledger slice as a self-verifying bundle."""
    from pathlib import Path
    from noosphere.ledger import KeyRing, export_bundle

    store = _get_store()
    keyring = KeyRing(store)
    result = export_bundle(store, keyring, from_id=from_id, to_id=to_id,
                           out_path=Path(out_path))
    if as_json:
        click.echo(json.dumps({"path": str(result)}, indent=2))
        return
    console.print(f"[bold green]✓ Bundle exported to {result}[/bold green]")

