44	const PUBLISH_CHECKLIST_KEYS = [
45	  "metaAnalysisOk",
46	  "adversarialEngagedOk",
47	  "clarityOk",
48	  "noLeakageOk",
49	  "noHarmOk",
50	] as const;
51	
52	export type PublishChecklist = Partial<Record<(typeof PUBLISH_CHECKLIST_KEYS)[number], boolean>>;
53	
54	function publicSiteBase(): string {
55	  const raw = process.env.THESEUS_PUBLIC_SITE_URL?.trim();
56	  if (raw) return raw.replace(/\/+$/, "");
57	  return "https://theseus.invalid";
58	}
59	
60	function assertChecklistForPublish(c: PublishChecklist) {
61	  for (const k of PUBLISH_CHECKLIST_KEYS) {
62	    if (!c[k]) {
63	      throw new Error(`Checklist incomplete: ${k}`);
64	    }
65	  }
66	}
