68	function escapeBibTitle(title: string): string {
69	  return title.replace(/[{}]/g, "").replace(/\\/g, "");
70	}
71	
72	function buildCitations(input: { slug: string; version: number; doi: string; title: string; year: number }) {
73	  const url = `${publicSiteBase()}/c/${encodeURIComponent(input.slug)}/v/${input.version}`;
74	  const key = `${input.slug.replace(/[^a-z0-9]+/gi, "")}_v${input.version}`.slice(0, 80);
75	  const bib = `@misc{theseus_${key},
76	  title={${escapeBibTitle(input.title)}},
77	  author={{Theseus}},
78	  year={${input.year}},
79	  doi={${input.doi}},
80	  url={${url}}
81	}`.trim();
82	  const apa = `Theseus (${input.year}). ${input.title}. ${url} https://doi.org/${input.doi}`;
83	  const ris = `TY  - GEN\nAU  - Theseus\nTI  - ${input.title}\nDO  - ${input.doi}\nUR  - ${url}\nPY  - ${input.year}\nER  -\n`;
84	  return [
85	    { format: "bibtex" as const, block: bib },
86	    { format: "apa" as const, block: apa },
87	    { format: "ris" as const, block: ris },
88	  ];
89	}
