91	export async function enqueuePublicationReview(params: {
92	  organizationId: string;
93	  conclusionId: string;
94	}): Promise<{ id: string }> {
95	  const c = await db.conclusion.findFirst({
96	    where: { id: params.conclusionId, organizationId: params.organizationId },
97	  });
98	  if (!c) {
99	    throw new Error("Conclusion not found");
100	  }
101	  if (c.confidenceTier !== "firm") {
102	    throw new Error("Only firm-tier conclusions may enter the publication queue");
103	  }
104	
105	  const active = await db.publicationReview.findFirst({
106	    where: {
107	      organizationId: params.organizationId,
108	      conclusionId: params.conclusionId,
109	      status: { in: ["queued", "in_review", "needs_revision"] },
110	    },
111	  });
112	  if (active) {
113	    throw new Error("This conclusion already has an active publication review");
114	  }
115	
116	  const row = await db.publicationReview.create({
117	    data: {
118	      organizationId: params.organizationId,
119	      conclusionId: params.conclusionId,
120	      status: "queued",
121	      checklistJson: "{}",
122	    },
123	  });
124	  return { id: row.id };
125	}
