141	export type PublicationReviewAction =
142	  | { action: "claim" }
143	  | { action: "release" }
144	  | { action: "checklist"; checklist: PublishChecklist; reviewerNotes?: string }
145	  | { action: "needs_revision"; revisionAsk: string; reviewerNotes?: string }
146	  | { action: "decline"; declineReason: string; reviewerNotes?: string }
147	  | {
148	      action: "publish";
149	      checklist: PublishChecklist;
150	      reviewerNotes?: string;
151	      evidenceSummary: string;
152	      exitConditions: string[];
153	      strongestObjection: { objection: string; firmAnswer: string };
154	      openQuestionsAdjacent: string[];
155	      voiceComparisons: { voice: string; stance: string }[];
156	      methodologyProfiles?: PublicationMethodologyProfile[];
157	      methodologyNarrative?: string;
158	      timeline?: { at: string; label: string; detail?: string }[];
159	      discountedConfidence: number;
160	      statedConfidence?: number;
161	      calibrationDiscountReason: string;
162	      slug?: string;
163	      zenodoTitle?: string;
164	    };
165	
166	function isReviewer(review: { reviewerFounderId: string | null }, founderId: string, role: string) {
167	  if (role === "admin") return true;
168	  return review.reviewerFounderId === founderId;
169	}
