171	export async function applyPublicationReviewAction(params: {
172	  organizationId: string;
173	  founderId: string;
174	  role: string;
175	  reviewId: string;
176	  body: PublicationReviewAction;
177	}): Promise<Record<string, unknown>> {
178	  const review = await db.publicationReview.findFirst({
179	    where: { id: params.reviewId, organizationId: params.organizationId },
180	    include: { target: true },
181	  });
182	  if (!review) {
183	    throw new Error("Review not found");
184	  }
185	
186	  switch (params.body.action) {
187	    case "claim": {
188	      if (review.status !== "queued" && review.status !== "needs_revision") {
189	        throw new Error("Cannot claim review in this state");
190	      }
191	      await db.publicationReview.update({
192	        where: { id: review.id },
193	        data: { status: "in_review", reviewerFounderId: params.founderId },
194	      });
195	      return { ok: true };
196	    }
197	    case "release": {
198	      if (!isReviewer(review, params.founderId, params.role)) {
199	        throw new Error("Only the assigned reviewer (or admin) can release a claim");
200	      }
201	      await db.publicationReview.update({
202	        where: { id: review.id },
203	        data: { status: "queued", reviewerFounderId: null },
204	      });
205	      return { ok: true };
206	    }
207	    case "checklist": {
208	      if (review.status !== "in_review") {
209	        throw new Error("Checklist updates require in_review");
210	      }
211	      if (!isReviewer(review, params.founderId, params.role)) {
212	        throw new Error("Only the assigned reviewer can edit the checklist");
213	      }
214	      await db.publicationReview.update({
215	        where: { id: review.id },
216	        data: {
217	          checklistJson: JSON.stringify(params.body.checklist ?? {}),
218	          reviewerNotes: params.body.reviewerNotes ?? review.reviewerNotes,
219	        },
220	      });
221	      return { ok: true };
222	    }
223	    case "needs_revision": {
224	      if (!isReviewer(review, params.founderId, params.role)) {
225	        throw new Error("Only the assigned reviewer can request revision");
226	      }
227	      await db.publicationReview.update({
228	        where: { id: review.id },
229	        data: {
230	          status: "needs_revision",
231	          revisionAsk: params.body.revisionAsk,
232	          reviewerNotes: params.body.reviewerNotes ?? review.reviewerNotes,
233	        },
234	      });
235	      return { ok: true };
236	    }
237	    case "decline": {
238	      if (!isReviewer(review, params.founderId, params.role)) {
239	        throw new Error("Only the assigned reviewer can decline");
240	      }
241	      await db.publicationReview.update({
242	        where: { id: review.id },
243	        data: {
244	          status: "declined",
245	          declineReason: params.body.declineReason,
246	          reviewerNotes: params.body.reviewerNotes ?? review.reviewerNotes,
247	        },
248	      });
249	      return { ok: true };
250	    }
251	    case "publish": {
252	      if (!isReviewer(review, params.founderId, params.role)) {
253	        throw new Error("Only the assigned reviewer can publish");
254	      }
255	      if (review.status !== "in_review") {
256	        throw new Error("Publish requires in_review status");
257	      }
258	      assertChecklistForPublish(params.body.checklist);
259	
260	      const exit = params.body.exitConditions.map((s) => s.trim()).filter(Boolean);
261	      if (exit.length === 0) {
262	        throw new Error("exitConditions required");
263	      }
264	      const objection = params.body.strongestObjection.objection.trim();
265	      const firmAnswer = params.body.strongestObjection.firmAnswer.trim();
266	      if (!objection || !firmAnswer) {
267	        throw new Error("strongestObjection.objection and .firmAnswer are required");
268	      }
269	
270	      const dc = params.body.discountedConfidence;
271	      if (typeof dc !== "number" || Number.isNaN(dc) || dc < 0 || dc > 1) {
272	        throw new Error("discountedConfidence must be between 0 and 1");
273	      }
274	
275	      const conclusion = review.target;
276	      const stated = params.body.statedConfidence ?? conclusion.confidence;
277	      let methodology: PublicationMethodology = parseMethodologyPayload({
278	        reviewerNarrative: params.body.methodologyNarrative,
279	        profiles: params.body.methodologyProfiles,
280	      });
281	      if (methodology.profiles.length === 0) {
282	        const profileMap = await profilesForConclusions(params.organizationId, [conclusion.id]);
283	        methodology = {
284	          ...methodology,
285	          profiles: profileMap.get(conclusion.id) ?? [],
286	        };
287	      }
288	
289	      const prev = await db.publishedConclusion.findFirst({
290	        where: { organizationId: params.organizationId, sourceConclusionId: conclusion.id },
291	        orderBy: { version: "desc" },
292	      });
293	      const nextVersion = (prev?.version ?? 0) + 1;
294	
295	      const baseSlug = (params.body.slug?.trim() || prev?.slug || publicationSlugFromText(conclusion.text)).slice(
296	        0,
297	        120,
298	      );
299	
300	      let slug = baseSlug;
301	      if (!prev) {
302	        const clash = await db.publishedConclusion.findFirst({
303	          where: { slug, version: 1 },
304	        });
305	        if (clash && clash.sourceConclusionId !== conclusion.id) {
306	          slug = `${baseSlug}-${conclusion.id.slice(0, 6)}`.slice(0, 120);
307	        }
308	      } else {
309	        slug = prev.slug;
310	      }
311	
312	      const publishedAt = new Date();
313	
314	      let priorTimeline: { at: string; label: string; detail?: string }[] = [];
315	      if (prev) {
316	        try {
317	          const priorPayload = JSON.parse(prev.payloadJson) as PublicationPayloadV1;
318	          priorTimeline = priorPayload.timeline ?? [];
319	          if (!hasMethodologyContent(methodology)) {
320	            methodology = parseMethodologyPayload(priorPayload.methodology);
321	          }
322	        } catch {
323	          priorTimeline = [];
324	        }
325	      }
326	      if (!hasMethodologyContent(methodology)) {
327	        throw new Error("methodology profile or reviewer methodology narrative is required");
328	      }
329	      const timeline =
330	        params.body.timeline?.length ?
331	          params.body.timeline
332	        : [
333	            ...priorTimeline,
334	            {
335	              at: publishedAt.toISOString(),
336	              label: nextVersion === 1 ? "Initial publication" : `Revision v${nextVersion}`,
337	            },
338	          ];
339	
340	      const whatWouldChangeOurMind = exit;
341	
342	      const payload: PublicationPayloadV1 = {
343	        schema: "theseus.publicConclusion.v1",
344	        conclusionText: conclusion.text,
345	        rationale: conclusion.rationale,
346	        topicHint: conclusion.topicHint,
347	        evidenceSummary: params.body.evidenceSummary.trim(),
348	        exitConditions: exit,
349	        strongestObjection: { objection, firmAnswer },
350	        openQuestionsAdjacent: params.body.openQuestionsAdjacent.map((s) => s.trim()).filter(Boolean),
351	        voiceComparisons: params.body.voiceComparisons,
352	        methodology,
353	        timeline,
354	        whatWouldChangeOurMind,
355	        citations: [],
356	      };
357	
358	      const draftTitle = (params.body.zenodoTitle ?? conclusion.text).slice(0, 240);
359	      const minted = await mintZenodoDoi({
360	        title: draftTitle,
361	        description: `${params.body.evidenceSummary.trim()}\n\n---\n\n${conclusion.text}`.slice(0, 48_000),
362	      });
363	
364	      payload.citations = buildCitations({
365	        slug,
366	        version: nextVersion,
367	        doi: minted.doi,
368	        title: draftTitle,
369	        year: publishedAt.getUTCFullYear(),
370	      });
371	
372	      const calibrationDiscountReason = params.body.calibrationDiscountReason.trim();
373	      const publishedChecklistJson = JSON.stringify(params.body.checklist);
374	      const publishedReviewerNotes = params.body.reviewerNotes ?? review.reviewerNotes;
375	
376	      await db.$transaction(async (tx) => {
377	        await tx.publishedConclusion.create({
378	          data: {
379	            organizationId: params.organizationId,
380	            sourceConclusionId: conclusion.id,
381	            slug,
382	            version: nextVersion,
383	            discountedConfidence: dc,
384	            statedConfidence: stated,
385	            calibrationDiscountReason,
386	            payloadJson: JSON.stringify(payload),
387	            doi: minted.doi,
388	            zenodoRecordId: minted.recordId,
389	            publishedAt,
390	          },
391	        });
392	        await tx.publicationReview.update({
393	          where: { id: review.id },
394	          data: {
395	            status: "published",
396	            checklistJson: publishedChecklistJson,
397	            reviewerNotes: publishedReviewerNotes,
398	          },
399	        });
400	      });
401	
402	      return { ok: true, slug, version: nextVersion, doi: minted.doi };
403	    }
404	    default:
405	      throw new Error("Unknown publication review action");
406	  }
407	}
