409	export async function buildPublicExportBundle(organizationId: string) {
410	  const pubs = await db.publishedConclusion.findMany({
411	    where: { organizationId },
412	    orderBy: [{ slug: "asc" }, { version: "asc" }],
413	  });
414	
415	  const openQuestions = await db.openQuestion.findMany({
416	    where: { organizationId },
417	    orderBy: { createdAt: "desc" },
418	    take: 500,
419	  });
420	
421	  const responses = await db.publicResponse.findMany({
422	    where: { organizationId, status: { in: ["approved", "engaged"] } },
423	    orderBy: { createdAt: "desc" },
424	    take: 500,
425	  });
426	
427	  const conclusions = pubs.map((p) => {
428	    const payload = parsePublicationPayload({ payloadJson: p.payloadJson, slug: p.slug });
429	    return {
430	      id: p.id,
431	      slug: p.slug,
432	      version: p.version,
433	      sourceConclusionId: p.sourceConclusionId,
434	      publishedAt: p.publishedAt.toISOString(),
435	      doi: p.doi,
436	      zenodoRecordId: p.zenodoRecordId,
437	      discountedConfidence: p.discountedConfidence,
438	      statedConfidence: p.statedConfidence,
439	      calibrationDiscountReason: p.calibrationDiscountReason,
440	      payload,
441	    };
442	  });
443	
444	  return {
445	    schema: "theseus.publishedExport.v1" as const,
446	    generatedAt: new Date().toISOString(),
447	    conclusions,
448	    openQuestions: openQuestions.map((q) => ({
449	      id: q.id,
450	      summary: q.summary,
451	      unresolvedReason: q.unresolvedReason,
452	      layerDisagreementSummary: q.layerDisagreementSummary,
453	      createdAt: q.createdAt.toISOString(),
454	    })),
455	    responses: responses.map((r) => ({
456	      id: r.id,
457	      publishedConclusionId: r.publishedConclusionId,
458	      kind: r.kind,
459	      body: r.body,
460	      citationUrl: r.citationUrl,
461	      status: r.status,
462	      createdAt: r.createdAt.toISOString(),
463	      pseudonymous: r.pseudonymous,
464	    })),
465	  };
