227	function evidenceObject(value: unknown): Record<string, unknown> {
228	  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
229	  return value as Record<string, unknown>;
230	}
231	
232	function isoDate(value: Date | string): string {
233	  return value instanceof Date ? value.toISOString() : String(value);
234	}
