236	function rowToMqs(row: MqsRow): MqsRecord {
237	  return {
238	    conclusionId: row.conclusionId,
239	    progressivity: num01(row.progressivity),
240	    severity: num01(row.severity),
241	    aimMethodFit: num01(row.aimMethodFit),
