252	export async function mqsForConclusion(
253	  organizationId: string,
254	  conclusionId: string,
255	): Promise<MqsRecord | null> {
256	  try {
257	    const rows = await db.$queryRaw<MqsRow[]>`
258	      SELECT
259	        "conclusionId",
260	        progressivity,
261	        severity,
262	        "aimMethodFit",
263	        compressibility,
264	        "domainSensitivity",
265	        composite,
